(112, 1, 'Administrador', 'created', 'ReporteEntrega', 18, NULL, '{\"nombre_cliente\":\"jhon mejias\",\"telefono_cliente\":\"941958045\",\"fecha_compra\":\"2026-02-12 00:00:00\",\"fecha_entrega\":\"2026-02-14 00:00:00\",\"turno_entrega\":\"manana\",\"nombre_destinatario\":\"Maria Gracia Garcia\",\"telefono_destinatario\":\"996138907\",\"distrito\":\"jesus_maria\",\"direccion_destinatario\":\"Jiron Costa Rica 140\",\"tipo_ubicacion\":\"casa\",\"dedicatoria\":\"Este 14 de febrero no solo celebro nuestro amor, sino la hermosa familia que hemos construido juntos. Gracias por ser mi compa\\u00f1era, mi apoyo y el coraz\\u00f3n de nuestro hogar.\\r\\n\\r\\nVerte como esposa y como madre de nuestro hijo me llena de orgullo y admiraci\\u00f3n cada d\\u00eda. Eres una mujer incre\\u00edble, fuerte, dulce y llena de amor.\\r\\nTE AMO \\r\\nJohn .\",\"costo_delivery\":\"20\",\"metodo_pago\":\"yape\",\"estado\":\"pendiente\",\"conductor_id\":null,\"nombre_conductor\":\"\",\"telefono_conductor\":\"\",\"created_by\":1,\"updated_at\":\"2026-02-12 10:59:46\",\"created_at\":\"2026-02-12 10:59:46\",\"id\":18}', '38.25.25.229', '2026-02-12 15:59:46'),
