(129, 1, 'Administrador', 'created', 'ReporteEntrega', 20, NULL, '{\"nombre_cliente\":\"Ernesto Jaimes\",\"telefono_cliente\":\"993453058\",\"fecha_compra\":\"2026-02-12 00:00:00\",\"fecha_entrega\":\"2026-02-14 00:00:00\",\"turno_entrega\":\"manana\",\"nombre_destinatario\":\"Mariella Feria\",\"telefono_destinatario\":\"993453058\",\"distrito\":\"santiago_surco\",\"direccion_destinatario\":\"Jiron Aguada Blanca 119 Dpto. 201\",\"tipo_ubicacion\":\"casa\",\"dedicatoria\":\"Hola Jamoncita, mi Jamoncita!!\\r\\n\\r\\nFeliz d\\u00eda de la mordida mi Jamoncita!!\\r\\n\\r\\nYa casi perd\\u00ed la cuenta, pero creo que ya es la d\\u00e9cima celebraci\\u00f3n Jamoncita!!\\u2026 aunque claro que al comienzo no hab\\u00edan mordidas \\ud83e\\udd14  pero si mucho amor y bastante calor, m\\u00e1s a\\u00fan en las noches de verano jejeje.\\r\\n\\r\\nSon ya casi 10 a\\u00f1os amorcito que estamos juntos y todos valieron el dolor, digo la pena, porque no me imagino hoy la vida sin ti, llegar a la casa y verte o recogerte cuando vienes de trabajar tan cansada que me da gana de cargarte hasta el carro, pero ya sabes, no se puede porque eres m\\u00e1s grande que yo.\\r\\n\\r\\nD\\u00e9cima celebraci\\u00f3n mi amor y nos queda mucho m\\u00e1s, muchas aventuras y retos que seguir superando juntos!! Te amo mi amorcito y espero siempre hacer todo lo posible para hacerte MUY FELIZ!!\\r\\n\\r\\n(Por ahora no te escribo m\\u00e1s porque mucho sapo, pero ya te lo dir\\u00e9 en persona)\\r\\n\\r\\nFELIZ D\\u00cdA DE SAN VALENT\\u00cdN MI BELLA PRINCESA!!! \\u2764\\ufe0f\\u2764\\ufe0f\\u2764\\ufe0f\\u2764\\ufe0f\\u2764\\ufe0f\\u2764\\ufe0f\\u2764\\ufe0f\\u2764\\ufe0f\\u2764\\ufe0f\\u2764\\ufe0f\",\"costo_delivery\":\"18\",\"metodo_pago\":\"plin\",\"estado\":\"pendiente\",\"conductor_id\":null,\"nombre_conductor\":\"\",\"telefono_conductor\":\"\",\"created_by\":1,\"updated_at\":\"2026-02-12 15:19:59\",\"created_at\":\"2026-02-12 15:19:59\",\"id\":20}', '38.25.25.229', '2026-02-12 20:19:59'),
(130, 1, 'Administrador', 'created', 'ReporteEntrega', 21, NULL, '{\"nombre_cliente\":\"Jorge Hoyos\",\"telefono_cliente\":\"978725040\",\"fecha_compra\":\"2026-02-12 00:00:00\",\"fecha_entrega\":\"2026-02-12 00:00:00\",\"turno_entrega\":\"tarde\",\"nombre_destinatario\":\"Jorge Hoyos\",\"telefono_destinatario\":\"978725040\",\"distrito\":\"surquillo\",\"direccion_destinatario\":\"Calle Victor Matilla 544\",\"tipo_ubicacion\":\"oficina\",\"dedicatoria\":\"Gracias por todo lo que haces por m\\u00ed, por nuestra familia y por todos los que te rodean. En este d\\u00eda del amor, recuerda que eres el gran amor de mi vida. TE AMO MI AMOR\\ud83d\\udc95\",\"costo_delivery\":\"0\",\"metodo_pago\":\"yape\",\"estado\":\"pendiente\",\"conductor_id\":null,\"nombre_conductor\":\"\",\"telefono_conductor\":\"\",\"created_by\":1,\"updated_at\":\"2026-02-12 15:24:29\",\"created_at\":\"2026-02-12 15:24:29\",\"id\":21}', '38.25.25.229', '2026-02-12 20:24:29'),
