(162, 1, 'Administrador', 'created', 'ReporteEntrega', 26, NULL, '{\"nombre_cliente\":\"alain\",\"telefono_cliente\":\"997893193\",\"fecha_compra\":\"2026-02-05 00:00:00\",\"fecha_entrega\":\"2026-02-13 00:00:00\",\"turno_entrega\":\"tarde\",\"nombre_destinatario\":\"frizzia villena bernal\",\"telefono_destinatario\":\"941366464\",\"distrito\":\"san_borja\",\"direccion_destinatario\":\"calle 10 414 monterrico norte\",\"enlace_ubicacion\":null,\"tipo_ubicacion\":\"casa\",\"dedicatoria\":\"Es nuestro 15vo d\\u00eda de los enamorados..!! Hoy somos esposos y tenemos una hermosa familia.  Agradezco a Dios por haber cruzado nuestros caminos y por darme la dicha de poder compartir contigo un a\\u00f1o m\\u00e1s...!!!  Aunque no necesito una fecha especial para recordarte cuanto te amo, espero que te guste este detalle.\",\"costo_delivery\":\"18\",\"metodo_pago\":\"izipay\",\"estado\":\"pendiente\",\"conductor_id\":null,\"nombre_conductor\":\"\",\"telefono_conductor\":\"\",\"created_by\":1,\"updated_at\":\"2026-02-12 19:47:22\",\"created_at\":\"2026-02-12 19:47:22\",\"id\":26}', '38.25.25.229', '2026-02-13 00:47:22'),
