(397, 1, 'Administrador', 'created', 'ReporteEntrega', 66, NULL, '{\"nombre_cliente\":\"carla\",\"telefono_cliente\":\"+19543933252\",\"fecha_compra\":\"2026-02-13 00:00:00\",\"fecha_entrega\":\"2026-02-14 00:00:00\",\"turno_entrega\":\"manana\",\"nombre_destinatario\":\"carla harumi\",\"telefono_destinatario\":\"976553631\",\"distrito\":\"san_miguel\",\"direccion_destinatario\":\"Avenida del pacifico 135 depto. 102\",\"enlace_ubicacion\":null,\"tipo_ubicacion\":\"casa\",\"dedicatoria\":\"Para mi amada esposa, Carla\\r\\n\\r\\nDesde que llegaste a mi vida, todo cambi\\u00f3 para bien. Eres mi paz en los d\\u00edas dif\\u00edciles, mi alegr\\u00eda en los momentos felices y la raz\\u00f3n por la que cada d\\u00eda quiero ser mejor.\\r\\n\\r\\nTu amor me levanta, me sana y me hace sentir en casa, sin importar la distancia. No necesito un mundo perfecto, solo te necesito a ti.\\r\\n\\r\\nHoy y siempre te elijo, te valoro y te amo con todo mi coraz\\u00f3n.\\r\\n\\r\\n\\u00a1Feliz D\\u00eda de San Valent\\u00edn!\\r\\n\\r\\nCon todo mi amor, tu esposo\\r\\nJordan\\r\\n14 de febrero de 2026\",\"costo_delivery\":\"25\",\"metodo_pago\":\"izipay\",\"estado\":\"pendiente\",\"conductor_id\":null,\"nombre_conductor\":\"\",\"telefono_conductor\":\"\",\"observacion\":null,\"es_urgente\":\"0\",\"created_by\":1,\"updated_at\":\"2026-02-13 21:20:57\",\"created_at\":\"2026-02-13 21:20:57\",\"id\":66}', '38.25.25.229', '2026-02-14 02:20:57'),
(398, 1, 'Administrador', 'created', 'ReporteEntrega', 67, NULL, '{\"nombre_cliente\":\"bryan\",\"telefono_cliente\":\"986825774\",\"fecha_compra\":\"2026-02-13 00:00:00\",\"fecha_entrega\":\"2026-02-14 00:00:00\",\"turno_entrega\":\"manana\",\"nombre_destinatario\":\"Karla Valencia\",\"telefono_destinatario\":\"919654350\",\"distrito\":\"pueblo_libre\",\"direccion_destinatario\":\"Cipriano dulanto 541 dpto. 203A\",\"enlace_ubicacion\":null,\"tipo_ubicacion\":\"casa\",\"dedicatoria\":\"\\u201cFeliz San Valentin Mi amor, espero que en este dia disfrutes todo el amor que siempre te dare, recuerda que siempre te amar\\u00e9 por toda la vida, mi princesa\\u201d\",\"costo_delivery\":\"20\",\"metodo_pago\":\"yape\",\"estado\":\"pendiente\",\"conductor_id\":null,\"nombre_conductor\":\"\",\"telefono_conductor\":\"\",\"observacion\":null,\"es_urgente\":\"0\",\"created_by\":1,\"updated_at\":\"2026-02-13 21:23:37\",\"created_at\":\"2026-02-13 21:23:37\",\"id\":67}', '38.25.25.229', '2026-02-14 02:23:47'),
