(930, 1, 'Administrador', 'created', 'ReporteEntrega', 94, NULL, '{\"nombre_cliente\":\"Andrea Lozada\",\"telefono_cliente\":\"947275559\",\"fecha_compra\":\"2026-02-19 00:00:00\",\"fecha_entrega\":\"2026-02-21 00:00:00\",\"turno_entrega\":\"manana\",\"nombre_destinatario\":\"Andrea Lozada\",\"telefono_destinatario\":\"974275559\",\"distrito\":\"san_juan_lurigancho\",\"direccion_destinatario\":\"Jiron las Grosellas 1030\",\"enlace_ubicacion\":null,\"tipo_ubicacion\":\"casa\",\"dedicatoria\":\"\\\"Feliz cumplea\\u00f1os, Martitha. Hoy celebro no solo un a\\u00f1o m\\u00e1s de tu vida, sino el regalo inmenso de tu presencia en la m\\u00eda. Que Dios y la Virgen gu\\u00eden cada uno de tus pasos, te rodeen de salud y protejan siempre ese coraz\\u00f3n tan noble que tienes.\\r\\n\\u200bTe env\\u00edo estas rosas como s\\u00edmbolo de una amistad que florece con el tiempo y que valoro profundamente. Gracias  por tu compa\\u00f1\\u00eda y por compartir un a\\u00f1o m\\u00e1s de camino conmigo. Que este nuevo ciclo est\\u00e9 lleno de amor y de sue\\u00f1os cumplidos. \\u00a1Te amo amiga!\\\"\",\"costo_delivery\":\"30\",\"metodo_pago\":\"izipay\",\"estado\":\"pendiente\",\"conductor_id\":null,\"nombre_conductor\":\"\",\"telefono_conductor\":\"\",\"observacion\":\"chocolate ferrero roche y 1 globo de feliz cumplea\\u00f1os\",\"es_urgente\":\"0\",\"created_by\":1,\"updated_at\":\"2026-02-19 09:50:35\",\"created_at\":\"2026-02-19 09:50:35\",\"id\":94}', '38.253.189.23', '2026-02-19 14:50:36'),
